import os, re, json, glob

reports_dir = \"/home/hugo/projects/python-benchmark/audit-reports/kimi_k2_6_ollama_codex\"
reports = sorted(glob.glob(os.path.join(reports_dir, \"*/report.md\")))

def extract_section(text, start_marker, end_marker=None, next_markers=None):
    # Find start
    start = text.find(start_marker)
    if start == -1:
        return None
    start += len(start_marker)
    # Find end
    if end_marker:
        end = text.find(end_marker, start)
        if end == -1:
            return text[start:]
        return text[start:end]
    if next_markers:
        positions = []
        for m in next_markers:
            p = text.find(m, start)
            if p "'!= -1:
                positions.append(p)
        if positions:
            return text[start:min(positions)]
        return text[start:]
    return text[start:]

def parse_report(path):
    with open(path, "r") as f:
        text = f.read()

    rel = os.path.relpath(path, "/home/hugo/projects/python-benchmark/audit-reports")
    # auditor is the directory name immediately above report.md'"'s parent
    parts = rel.split(os.sep)
    auditor = parts[0] if len(parts) >= 2 else \"unknown\"
    harness_model = parts[1] if len(parts) >= 3 else \"unknown\"
    harness = harness_model.split(\"-\")[0]
    model_slug = \"-\".join(harness_model.split(\"-\")[1:])

    data = {
        \"path\": rel,
        \"abs_path\": path,
        \"auditor\": auditor,
        \"harness\": harness,
        \"model_slug\": model_slug,
        \"harness_model\": harness_model,
        \"dimensions\": {},
        \"total\": None,
        \"tier\": None,
        \"critical_failures\": [],
        \"metrics\": {}
    }

    # Extract dimensions from section B
    # Look for table rows like: # | Dimension | Score / Max | ...
    dim_pattern = re.compile(r\""'^'"\\s*(\\d+)\\s*\\|\\s*(["'^|]+)'"\\|\\s*(\\d+)\\s*/\\s*(\\d+)\\s*\\|\", re.MULTILINE)
    for m in dim_pattern.finditer(text):
        idx = int(m.group(1))
        score = int(m.group(3))
        maxv = int(m.group(4))
        if 1 <= idx <= 9:
            data[\"dimensions\"][f\"D{idx}\"] = {\"score\": score, \"max\": maxv}

    # Also try alternate patterns like \"D1 | ... | 20/25\"
    alt_pattern = re.compile(r\"\\b(D\\d)\\b\\s*\\|\\s*["'^|]*'"\\|\\s*(\\d+)\\s*/\\s*(\\d+)\", re.MULTILINE)
    for m in alt_pattern.finditer(text):
        d = m.group(1)
        score = int(m.group(2))
        maxv = int(m.group(3))
        if d not in data[\"dimensions\"]:
            data[\"dimensions\"][d] = {\"score\": score, \"max\": maxv}

    # Total from section C
    total_match = re.search(r\"C\\.\\s*\\*\\*Total score\\s*/\\s*100\\*\\*.*?([0-9]+)\\s*/\\s*100\", text, re.DOTALL)
    if not total_match:
        total_match = re.search(r\"Total score\\s*[:/]?\\s*([0-9]+)\\s*/\\s*100\", text, re.DOTALL)
    if not total_match:
        total_match = re.search(r\"([0-9]+)\\s*/\\s*100\", text)
    if total_match:
        data[\"total\"] = int(total_match.group(1))

    # Tier from section D
    tier_match = re.search(r\"\\*\\*([ABCD])\\s*\\(\\s*\\d+\\s*-\\s*\\d+\\s*\\)\\*\\*\", text)
    if not tier_match:
        tier_match = re.search(r\"Tier\\s*[:\\-]?\\s*\\*?([ABCD])\\b\", text, re.IGNORECASE)
    if tier_match:
        data[\"tier\"] = tier_match.group(1)

    # Critical failures from section F
    cf_section = extract_section(text, \"F. **Critical Failures**\", \"G. **Critical-failure ledger**\")
    if cf_section is None:
        cf_section = extract_section(text, \"## F. Critical Failures\", \"## G.\")
    if cf_section is None:
        cf_section = extract_section(text, \"**Critical Failures**\", \"**Critical-failure ledger**\")
    if cf_section:
        # Look for CF type numbers
        cf_types = re.findall(r\"CF\\s*#?\\s*(\\d+)\", cf_section)
        for ct in cf_types:
            data[\"critical_failures\"].append(int(ct))
        # Also look for numbered lists if no explicit CF#
        if not cf_types:
            lines = [l for l in cf_section.splitlines() if l.strip().startswith(\"-\") or l.strip().startswith(\"*\")]
            # Just store count
            data[\"cf_count\"] = len(lines)

    # Metrics from section H
    h_section = extract_section(text, \"H. **Submission metadata\", None, [\"I. **Killer\", \"## I.\"])
    if h_section is None:
        h_section = extract_section(text, \"## H. Submission metadata\", None, [\"## I.\", \"I. **Killer\"])
    if h_section is None:
        h_section = extract_section(text, \"**Submission metadata\", None, [\"**Killer\", \"I. **Killer\"])

    if h_section:
        # Extract key-value pairs
        for line in h_section.splitlines():
            line = line.strip()
            if \"Generation-Time\" in line and \":\" in line:
                data[\"metrics\"][\"generation_time\"] = line.split(\":\", 1)[1].strip().replace(\""'`", "").strip()
            elif "Input-Tokens" in line and ":" in line:
                data["metrics"]["input_tokens"] = line.split(":", 1)[1].strip().replace("`", "").strip()
            elif "Output-Tokens" in line and ":" in line:
                data["metrics"]["output_tokens"] = line.split(":", 1)[1].strip().replace("`", "").strip()
            elif "Total-Tokens" in line and ":" in line:
                data["metrics"]["total_tokens"] = line.split(":", 1)[1].strip().replace("`", "").strip()
            elif "Estimated-Cost-USD" in line and ":" in line:
                data["metrics"]["cost_usd"] = line.split(":", 1)[1].strip().replace("`", "").strip()
            elif "Prompt-Version" in line and ":" in line:
                data["metrics"]["prompt_version"] = line.split(":", 1)[1].strip().replace("`", "").strip()

    return data

results = []
