def safe_mean(vals):
    return sum(vals)/len(vals) if vals else 0

def safe_std(vals):
    if len(vals) < 2:
        return 0.0
    return statistics.stdev(vals)

def safe_median(vals):
    if not vals:
        return 0
    s = sorted(vals)
    n = len(s)
    if n % 2 == 1:
        return s[n//2]
    return (s[n//2 - 1] + s[n//2]) / 2

def tier_band(score):
    if score is None:
        return None
    if score >= 81:
        return "A"
    if score >= 61:
        return "B"
    if score >= 41:
        return "C"
    return "D"

