def parse_cost(val):
    if not val or val.lower() in (\"n/a\", \"na\"):
        return None
    m = re.search(r\"[\\d,]+\\.?\\d*\", val.replace(\",\", \"\"))
    if m:
        try:
            return float(m.group(0).replace(\",\", \"\"))
        except:
            return None
    return None

def parse_time(val):
    if not val or val.lower() in (\"n/a\", \"na\"):
        return None
    m = re.search(r\"([\\d,]+\\.?\\d*)\", val.replace(\",\", \"\"))
    if m:
        try:
            return float(m.group(1).replace(\",\", \"\")) / 60.0
        except:
            return None
    return None

def parse_tokens(val):
    if not val or val.lower() in (\"n/a\", \"na\"):
        return None
    m = re.search(r\"([\\d,]+)\", val.replace(\",\", \"\"))
    if m:
        try:
            return int(m.group(1).replace(\",\", \"\"))
        except:
            return None
    return None

