    if n == 0:
        continue
    avg_score = safe_mean([s for s,m in entries])
    avg_max = safe_mean([m for s,m in entries])
    cl = dim_stats[d]["claude"]
    co = dim_stats[d]["codex"]
    op = dim_stats[d]["opencode"]
    cl_avg = safe_mean([s for s,m in cl]) if cl else 0
    co_avg = safe_mean([s for s,m in co]) if co else 0
    op_avg = safe_mean([s for s,m in op]) if op else 0

    full_marks = sum(1 for s,m in entries if s >= m)
    sat = full_marks / n >= 0.80 if n > 0 else False
    zeros = sum(1 for s,m in entries if s == 0)
    flr = zeros / n >= 0.80 if n > 0 else False
    harness_avgs = [a for a in [cl_avg, co_avg, op_avg] if a > 0]
    har_att = max(harness_avgs) - min(harness_avgs) >= 2 if len(harness_avgs) >= 2 else False
    pct = (avg_score / avg_max * 100) if avg_max else 0
    ub = (max(harness_avgs) - min(harness_avgs) <= 1 if len(harness_avgs) >= 2 else True) and pct < 70
    clean = (pct >= 80) and not sat

    if sat:
        classification = "saturated"
    elif flr:
        classification = "universal blind spot (floor)"
    elif ub:
        classification = "universal blind spot"
    elif har_att:
        classification = "harness-attributable"
    elif clean:
        classification = "clean"
    else:
        classification = "mixed"

    L(f"- **{d} — {label}** (max {int(avg_max)}): universal-avg {avg_score:.1f}; per-harness avg claude={cl_avg:.1f} / codex={co_avg:.1f} / opencode={op_avg:.1f}. Classify as **{classification}**.")
